```php
// In mytheme.theme
function mytheme_preprocess_node(&$variables) {
  $node = $variables['node'];
  $author = $node->getOwner();
  $variables['author_name'] = $author->getDisplayName();
  $variables['date'] = date('F j, Y', $node->getCreatedTime());

  $tags = [];
  foreach ($node->get('field_tags') as $tag) {
    $tags[] = $tag->entity->getName();
  }
  $variables['tags'] = $tags;
}
```

